from pyiceberg.catalog.rest import RestCatalog, Endpoints, NoSuchTableError, TableAlreadyExistsError

class DummySession:
    def __init__(self, status_code):
        self._status = status_code
        self.last_request = None
    def post(self, url, json):
        resp = Response()
        resp.status_code = self._status
        self.last_request = (url, json)
        return resp

class DummyCatalog(RestCatalog):
    def __init__(self, status_code):
        super().__init__("dummy://")
        self._session = DummySession(status_code)
        self._loaded = None
    def load_table(self, identifier):
