/// instead of an internal stored batch, leading to non-equivalence.
#[cfg(test)]
mod default_writer_mismatch {
    use super::*;
    use arrow_array::{RecordBatch, Int64Array};
    use std::sync::{Arc, Mutex};

    struct DummyWriter {
        batches: Arc<Mutex<Vec<RecordBatch>>>,
    }

    impl DummyWriter {
        fn new(batches: Arc<Mutex<Vec<RecordBatch>>>) -> Self {
            Self { batches }
        }
    }

    #[async_trait::async_trait]
    impl crate::writer::file_writer::FileWriter for DummyWriter {
        fn write(&mut self, batch: &RecordBatch) -> impl std::future::Future<Output = Result<()>> + Send {
            let batch_clone = batch.clone();
            let batches = self.batches.clone();
            async move {
                batches.lock().unwrap().push(batch_clone);
                Ok(())
            }
        }
        fn close(self) -> impl std::future::Future<Output = Result<Vec<crate::spec::DataFileBuilder>>> + Send {
            async { Ok(vec![]) }
        }
    }

    #[derive(Clone)]
    struct DummyBuilder {
        batches: Arc<Mutex<Vec<RecordBatch>>>,
    }

    impl crate::writer::file_writer::FileWriterBuilder for DummyBuilder {
        type R = DummyWriter;
        fn build(self) -> impl std::future::Future<Output = Result<Self::R>> + Send {
            let batches = self.batches.clone();
            async move { Ok(DummyWriter::new(batches)) }
        }
    }

    #[tokio::test]
    async fn test_data_file_writer_writes_passed_batch_not_stored_value() {
        let batches = Arc::new(Mutex::new(Vec::new()));
        let builder = DummyBuilder { batches: batches.clone() };
        let writer = crate::writer::base_writer::data_file_writer::DataFileWriterBuilder::new(builder)
            .build(crate::writer::base_writer::data_file_writer::DataFileWriterConfig::new(None))
            .await
            .unwrap();
        let mut writer = writer;
        // create a RecordBatch with a single Int64 column [1, 2]
        let array = Arc::new(Int64Array::from(vec![1i64, 2]));
        let batch = RecordBatch::try_from_iter(vec![("col", array.clone() as ArrayRef)]).unwrap();
        writer.write(batch.clone()).await.unwrap();
        // The batch recorded should be exactly the passed batch
        let recorded = batches.lock().unwrap();
        assert_eq!(recorded.len(), 1);
        assert_eq!(recorded[0], batch);
    }
}

