    Ok(r) => r.table,
    Err(_) => return Err(GlueErrorKind::NotFound(
      format!("Cannot rename {:?} because the table does not exist in Glue", from)
    )),
  };

  // ... same creation logic ...

  match self.drop_table(from).await {
    Ok(()) => Ok(()),
    Err(e) => {
      // rollback
      if let Err(del_err) = self.client.delete_table(...).send().await {
        return Err(GlueErrorKind::DeleteFailed(
          format!("Rollback delete failed after rename: {:?}", del_err)
        ));
      }
      Err(e)
    }
  }
}
