async fn rename_table(&self, from: &TableIdent, to: &TableIdent) -> Result<()> {
    // Check if new namespace exists
    if !self.namespace_exists(&to.namespace()).await? {
        return Err(Error::new(
            ErrorKind::DataInvalid,
            format!("Cannot rename {:?} to {:?} because namespace {:?} does not exist", from, to, to.namespace()),
        ));
    }

    // If skip_name_validation config is set, bypass strict validation
    let from_db_name = if self.config.skip_name_validation {
        from.namespace().to_string()
    } else {
        validate_namespace(from.namespace())?
    };
    let from_table_name = if self.config.skip_name_validation {
        from.name().to_string()
    } else {
        validate_table_name(from.name())?
    };
    let to_db_name = if self.config.skip_name_validation {
        to.namespace().to_string()
    } else {
        validate_namespace(to.namespace())?
    };
    let to_table_name = if self.config.skip_name_validation {
        to.name().to_string()
    } else {
        validate_table_name(to.name())?
    };

    // Get the source table
    let builder = self
        .client
        .0
        .get_table()
        .database_name(&from_db_name)
        .name(&from_table_name);
    let builder = with_catalog_id!(builder, self.config);
    let from_table = match builder.send().await {
        Ok(response) => response.table,
        Err(e) => {
            return Err(Error::new(
                ErrorKind::Unexpected,
                format!("Cannot rename {:?} because the table does not exist in Glue", from),
            ).with_source(anyhow!("aws sdk error: {:?}", e)));
        }
    };

    // Create the new table with the same Glue info, pointing to the old metadata
    let table_input = TableInput::builder()
        .name(&to_table_name)
        .owner(from_table.owner())
        .table_type(from_table.table_type())
        .parameters(from_table.parameters)
        .storage_descriptor(from_table.storage_descriptor)
        .build()
        .map_err(from_aws_build_error)?;

    let builder = self
        .client
        .0
        .create_table()
        .database_name(&to_db_name)
        .table_input(table_input);
    let builder = with_catalog_id!(builder, self.config);
    builder.send().await.map_err(from_aws_sdk_error)?;

    log::info!("created rename destination table {:?}", to);

    // Try to drop the old table
    match self.drop_table(from).await {
        Ok(_) => {
            log::info!("Successfully renamed table from {:?} to {:?}", from, to);
            Ok(())
        }
        Err(e) => {
            // Rollback: delete renamed table
            log::error!(
                "Fail to drop old table {:?} after renaming to {:?}, rollback to use the old table",
                from,
                to
            );
            let builder = self
                .client
                .0
                .delete_table()
                .database_name(&to_db_name)
                .name(&to_table_name);
            let builder = with_catalog_id!(builder, self.config);
            builder.send().await.map_err(from_aws_sdk_error)?;
            Err(e)
        }
    }
}
